/** Cryptographic proof for a statement. */
export type StatementProof =
  /** Sr25519 signature proof. */
  | { tag: "Sr25519"; value: { signature: Uint8Array; signer: Uint8Array } }
  /** Ed25519 signature proof. */
  | { tag: "Ed25519"; value: { signature: Uint8Array; signer: Uint8Array } }
  /** ECDSA signature proof. */
  | { tag: "Ecdsa"; value: { signature: Uint8Array; signer: Uint8Array } }
  /** On-chain event proof. */
  | {
      tag: "OnChain";
      value: { who: Uint8Array; blockHash: Uint8Array; event: bigint };
    };

export const StatementProof: S.Codec<StatementProof> = S.lazy(
  (): S.Codec<StatementProof> =>
    S.taggedUnion({
      Sr25519: S.struct({
        signature: S.byteArray(64),
        signer: S.byteArray(32),
      }) as S.Codec<{ signature: Uint8Array; signer: Uint8Array }>,
      Ed25519: S.struct({
        signature: S.byteArray(64),
        signer: S.byteArray(32),
      }) as S.Codec<{ signature: Uint8Array; signer: Uint8Array }>,
      Ecdsa: S.struct({
        signature: S.byteArray(65),
        signer: S.byteArray(33),
      }) as S.Codec<{ signature: Uint8Array; signer: Uint8Array }>,
      OnChain: S.struct({
        who: S.byteArray(32),
        blockHash: S.byteArray(32),
        event: S.u64,
      }) as S.Codec<{ who: Uint8Array; blockHash: Uint8Array; event: bigint }>,
    }),
);

